const html = $input.item.json.data;

const techSignals = {
  "React": /react\.js|react-dom/i,
  "Next.js": /next\.js|_next\/static/i,
  "Vue": /vue\.js|vuex/i,
  "Angular": /angular\.js|ng-version/i,
  "Shopify": /shopify|myshopify\.com/i,
  "WordPress": /wp-content|wp-includes/i,
  "HubSpot": /hubspot\.com|hs-scripts/i,
  "Salesforce": /salesforce\.com|pardot/i,
  "Segment": /segment\.com|analytics\.js/i,
  "Intercom": /intercom\.com|intercomcdn/i,
  "Stripe": /stripe\.com\/v3/i,
  "AWS": /amazonaws\.com/i,
  "Vercel": /vercel\.app|vercel\.com/i,
};

const detected = Object.entries(techSignals)
  .filter(([_, regex]) => regex.test(html))
  .map(([tech]) => tech);

return { techStack: detected, rawHtml: html.slice(0, 500) };

