const webhookData = $('Webhook').item.json;
const techStackData = $('Code in JavaScript').item.json;
const caseStudyData = $('HTTP Request2').item.json;
const emailData = $('Message a model').item.json;

return {
  url: webhookData?.body?.url || "not found",
  techStack: techStackData?.techStack ? techStackData.techStack.join(', ') : "not found",
  caseStudy: caseStudyData?.data?.documents?.[0]?.title || "not found",
  emailDraft: emailData?.content?.parts?.[0]?.text || "not found",
  createdAt: new Date().toISOString()
};
